import React, { useState, useEffect, useRef } from "react";
import { X, Mic, MicOff, ShoppingCart, Plus, Trash2, Edit3, Volume2, AlertCircle, Smartphone } from "lucide-react";
import { wordsToNumbers } from 'words-to-numbers';

// Enhanced product database with more realistic data
const productDatabase = [
  { id: 1, item: "Apple iPhone 15", brand: "Apple", rate: 79900, category: "Electronics" },
  { id: 2, item: "Samsung Galaxy S24", brand: "Samsung", rate: 74999, category: "Electronics" },
  { id: 3, item: "Laptop Dell XPS", brand: "Dell", rate: 89999, category: "Electronics" },
  { id: 4, item: "Wireless Headphones", brand: "Sony", rate: 15999, category: "Electronics" },
  { id: 5, item: "Coffee Beans", brand: "Starbucks", rate: 899, category: "Food" },
  { id: 6, item: "Green Tea", brand: "Twinings", rate: 450, category: "Beverages" },
  { id: 7, item: "Protein Powder", brand: "Optimum", rate: 3500, category: "Health" },
  { id: 8, item: "Running Shoes", brand: "Nike", rate: 8999, category: "Sports" }
];

const knownUnits = ['kg', 'kilogram', 'g', 'gram', 'liters', 'liter', 'bottles', 'packets', 'pieces', 'dozen', 'box', 'boxes', 'l', 'ml', 'milliliter', 'cups', 'pints', 'quarts', 'ounces', 'units', 'pair', 'pairs'];

// Utility functions
function detectUnit(itemStr) {
  if (typeof itemStr !== 'string') {
    console.warn('Expected string but got:', typeof itemStr, itemStr);
    return { unit: 'unit', item: 'unknown' };
  }
  const words = itemStr.trim().toLowerCase().split(/\s+/);

  if (knownUnits.includes(words[0])) {
    return {
      unit: words[0],
      item: words.slice(1).join(' ') || 'unknown'
    };
  }

  const last = words[words.length - 1];
  if (knownUnits.includes(last)) {
    return {
      unit: last,
      item: words.slice(0, -1).join(' ') || 'unknown'
    };
  }

  return {
    unit: 'unit',
    item: itemStr.trim()
  };
}

function parseMultipleOrders(transcript) {
  if (typeof transcript !== 'string') {
    console.error('Invalid input: transcript must be a string');
    return [];
  }

  let normalized;
  try {
    transcript = transcript.replace(/[^a-zA-Z0-9\s.,]/g, '');
    transcript = transcript.replace(/\s+/g, ' ').trim();
    transcript = transcript.replace(/\bto\b/g, "two");
    normalized = wordsToNumbers(transcript);
  } catch (error) {
    console.error('Error converting words to numbers:', error);
    normalized = transcript;
  }

  console.log("Normalized transcript:", normalized);

  const orders = [];
  const regex = /(\d+(?:\.\d+)?)\s+([a-zA-Z][a-zA-Z\s]*?)(?=\s+\d+|$)/g;

  let match;
  while ((match = regex.exec(normalized)) !== null) {
    const [, quantity, itemText] = match;
    const { unit, item } = detectUnit(itemText.trim());

    orders.push({
      item,
      quantity: parseFloat(quantity),
      unit
    });

    console.log(`Parsed: ${quantity} × ${itemText.trim()} (${unit})`);
  }

  return orders;
}

const parseOrderFromText = (text) => {
  return parseMultipleOrders(text);
};

const generateOrderId = () => {
  const timestamp = Date.now();
  const randomNum = Math.floor(Math.random() * 1000);
  return `ORD${timestamp.toString().slice(-6)}${randomNum.toString().padStart(3, '0')}`;
};

// Mobile detection utility
const isMobile = () => {
  return /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
};

const CreateOrder = ({ isOpen, onClose, onAddOrder }) => {
  // State management
  const [orderData, setOrderData] = useState({
    customerName: '',
    orderId: generateOrderId(),
    items: []
  });

  const [voiceInput, setVoiceInput] = useState({
    transcript: '',
    isListening: false,
    isSupported: false,
    interimTranscript: '',
    finalTranscript: ''
  });

  const [manualItem, setManualItem] = useState({
    item: '',
    quantity: 1,
    unit: 'pieces',
    rate: 0
  });

  const [errors, setErrors] = useState({});
  const [activeTab, setActiveTab] = useState('voice');
  const [deviceInfo, setDeviceInfo] = useState({
    isMobile: false,
    browser: '',
    supportLevel: 'unknown'
  });

  const recognitionRef = useRef(null);
  const textareaRef = useRef(null);
  const timeoutRef = useRef(null);

  // Enhanced Speech Recognition Setup with mobile optimizations
  const initializeSpeechRecognition = () => {
    if (typeof window === 'undefined') return null;

    const mobile = isMobile();
    const userAgent = navigator.userAgent.toLowerCase();
    let browser = 'unknown';

    if (userAgent.includes('chrome')) browser = 'chrome';
    else if (userAgent.includes('safari')) browser = 'safari';
    else if (userAgent.includes('firefox')) browser = 'firefox';
    else if (userAgent.includes('edge')) browser = 'edge';

    setDeviceInfo({ isMobile: mobile, browser, supportLevel: 'checking' });

    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      const recognition = new SpeechRecognition();

      // Mobile-optimized settings
      recognition.continuous = mobile ? false : true; // Mobile works better with non-continuous
      recognition.interimResults = true; // Enable interim results for better UX
      recognition.lang = 'en-US';
      recognition.maxAlternatives = 1;

      // Mobile-specific optimizations
      if (mobile) {
        recognition.grammars = null; // Disable grammars on mobile for better performance
      }

      recognition.onstart = () => {
        console.log('Speech recognition started');
        setVoiceInput(prev => ({ 
          ...prev, 
          isListening: true,
          interimTranscript: '',
          finalTranscript: prev.finalTranscript || prev.transcript
        }));
        setErrors(prev => ({ ...prev, voice: '' }));

        // Auto-stop after 30 seconds on mobile to prevent hanging
        if (mobile) {
          timeoutRef.current = setTimeout(() => {
            recognition.stop();
          }, 30000);
        }
      };

      recognition.onresult = (event) => {
        let interimTranscript = '';
        let finalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; i++) {
          const transcript = event.results[i][0].transcript;

          if (event.results[i].isFinal) {
            finalTranscript += transcript + ' ';
          } else {
            interimTranscript += transcript;
          }
        }

        setVoiceInput(prev => ({
          ...prev,
          interimTranscript,
          finalTranscript: prev.finalTranscript + finalTranscript,
          transcript: prev.finalTranscript + finalTranscript + interimTranscript
        }));

        // On mobile, auto-restart recognition if it stops unexpectedly
        if (mobile && finalTranscript) {
          clearTimeout(timeoutRef.current);
          timeoutRef.current = setTimeout(() => {
            if (recognition && voiceInput.isListening) {
              try {
                recognition.start();
              } catch (e) {
                console.log('Recognition restart failed:', e);
              }
            }
          }, 1000);
        }
      };

      recognition.onerror = (event) => {
        console.error('Speech recognition error:', event.error, event);
        setVoiceInput(prev => ({ ...prev, isListening: false }));
        clearTimeout(timeoutRef.current);

        const errorMessages = {
          'not-allowed': mobile ? 
            'Microphone access denied. Please enable microphone in your browser settings and reload the page.' :
            'Microphone access denied. Please allow microphone permissions.',
          'no-speech': mobile ?
            'No speech detected. Please speak clearly and try again. Make sure you\'re in a quiet environment.' :
            'No speech detected. Please try speaking clearly.',
          'network': 'Network error. Please check your internet connection and try again.',
          'audio-capture': mobile ?
            'No microphone found. Please check your device microphone settings.' :
            'No microphone found. Please check your audio settings.',
          'service-not-allowed': mobile ?
            'Speech service not available. Try using Chrome or Safari browser.' :
            'Speech recognition service not available.',
          'aborted': 'Speech recognition was stopped.',
          'language-not-supported': 'Language not supported. Please use English.'
        };

        setErrors(prev => ({ 
          ...prev, 
          voice: errorMessages[event.error] || `Speech recognition error: ${event.error}. ${mobile ? 'Try using Chrome browser for better compatibility.' : ''}` 
        }));

        // Update support level based on error
        if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
          setDeviceInfo(prev => ({ ...prev, supportLevel: 'blocked' }));
        }
      };

      recognition.onend = () => {
        console.log('Speech recognition ended');
        setVoiceInput(prev => ({ 
          ...prev, 
          isListening: false,
          transcript: prev.finalTranscript + prev.interimTranscript,
          interimTranscript: ''
        }));
        clearTimeout(timeoutRef.current);

        // On mobile, if we ended unexpectedly and were still supposed to be listening
        if (mobile && voiceInput.isListening) {
          setTimeout(() => {
            if (voiceInput.isListening) {
              try {
                recognition.start();
              } catch (e) {
                console.log('Auto-restart failed:', e);
                setVoiceInput(prev => ({ ...prev, isListening: false }));
              }
            }
          }, 100);
        }
      };

      setVoiceInput(prev => ({ ...prev, isSupported: true }));
      setDeviceInfo(prev => ({ ...prev, supportLevel: 'supported' }));
      return recognition;
    } else {
      setVoiceInput(prev => ({ ...prev, isSupported: false }));
      setDeviceInfo(prev => ({ ...prev, supportLevel: 'unsupported' }));
      return null;
    }
  };

  // Effects
  useEffect(() => {
    if (isOpen) {
      recognitionRef.current = initializeSpeechRecognition();
      setOrderData(prev => ({ ...prev, orderId: generateOrderId() }));
    }

    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
    };
  }, [isOpen]);

  // Event handlers
  const startVoiceRecognition = () => {
    if (!recognitionRef.current) {
      setErrors(prev => ({ 
        ...prev, 
        voice: `Speech recognition not supported in ${deviceInfo.browser} browser. ${deviceInfo.isMobile ? 'Try using Chrome or Safari.' : ''}` 
      }));
      return;
    }

    // Request microphone permission explicitly on mobile
    if (deviceInfo.isMobile && navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
      navigator.mediaDevices.getUserMedia({ audio: true })
        .then(() => {
          startRecognition();
        })
        .catch((error) => {
          console.error('Microphone permission error:', error);
          setErrors(prev => ({ 
            ...prev, 
            voice: 'Microphone access required. Please allow microphone access and try again.' 
          }));
        });
    } else {
      startRecognition();
    }
  };

  const startRecognition = () => {
    try {
      // Reset transcripts
      setVoiceInput(prev => ({
        ...prev,
        transcript: '',
        finalTranscript: '',
        interimTranscript: ''
      }));

      recognitionRef.current.start();
      console.log('Starting speech recognition...');
    } catch (error) {
      console.error('Error starting speech recognition:', error);

      if (error.name === 'NotAllowedError') {
        setErrors(prev => ({ 
          ...prev, 
          voice: deviceInfo.isMobile ?
            'Microphone blocked. Go to your browser settings, enable microphone for this site, and reload the page.' :
            'Please allow microphone access in your browser settings.' 
        }));
      } else if (error.name === 'InvalidStateError') {
        // Recognition already running, stop it first
        recognitionRef.current.stop();
        setTimeout(() => {
          try {
            recognitionRef.current.start();
          } catch (e) {
            setErrors(prev => ({ ...prev, voice: 'Could not start voice input. Please try again.' }));
          }
        }, 100);
      } else {
        setErrors(prev => ({ 
          ...prev, 
          voice: `Could not start voice input: ${error.message}. ${deviceInfo.isMobile ? 'Try refreshing the page.' : ''}` 
        }));
      }
    }
  };

  const stopVoiceRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
    }
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }
    setVoiceInput(prev => ({ ...prev, isListening: false }));
  };

  const parseVoiceOrder = () => {
    const textToParse = voiceInput.finalTranscript || voiceInput.transcript;
    const parsedItems = parseOrderFromText(textToParse);

    if (parsedItems.length === 0) {
      setErrors(prev => ({ ...prev, parse: 'Could not parse any items from the transcript. Please try again or use manual entry.' }));
      return;
    }

    const mappedItems = parsedItems.map(parsedItem => {
      const matchingProduct = productDatabase.find(
        product => 
          product.item.toLowerCase().includes(parsedItem.item.toLowerCase()) ||
          parsedItem.item.toLowerCase().includes(product.item.toLowerCase().split(' ')[0])
      );

      return {
        id: Date.now() + Math.random(),
        item: matchingProduct ? matchingProduct.item : parsedItem.item,
        brand: matchingProduct ? matchingProduct.brand : "Unknown Brand",
        quantity: parsedItem.quantity || 1,
        rate: matchingProduct ? matchingProduct.rate : 100,
        unit: parsedItem.unit || "pieces"
      };
    });

    setOrderData(prev => ({ ...prev, items: [...prev.items, ...mappedItems] }));
    setVoiceInput(prev => ({ 
      ...prev, 
      transcript: '', 
      finalTranscript: '', 
      interimTranscript: '' 
    }));
    setErrors(prev => ({ ...prev, parse: '' }));
  };

  const addManualItem = () => {
    if (!manualItem.item.trim()) {
      setErrors(prev => ({ ...prev, manual: 'Please enter an item name.' }));
      return;
    }

    if (manualItem.quantity <= 0) {
      setErrors(prev => ({ ...prev, manual: 'Quantity must be greater than 0.' }));
      return;
    }

    const matchingProduct = productDatabase.find(
      product => product.item.toLowerCase().includes(manualItem.item.toLowerCase())
    );

    const newItem = {
      id: Date.now() + Math.random(),
      item: manualItem.item,
      brand: matchingProduct ? matchingProduct.brand : "Custom Brand",
      quantity: manualItem.quantity,
      rate: manualItem.rate || (matchingProduct ? matchingProduct.rate : 100),
      unit: manualItem.unit
    };

    setOrderData(prev => ({ ...prev, items: [...prev.items, newItem] }));
    setManualItem({ item: '', quantity: 1, unit: 'pieces', rate: 0 });
    setErrors(prev => ({ ...prev, manual: '' }));
  };

  const removeItem = (itemId) => {
    setOrderData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== itemId)
    }));
  };

  const updateItemQuantity = (itemId, newQuantity) => {
    if (newQuantity <= 0) return;

    setOrderData(prev => ({
      ...prev,
      items: prev.items.map(item => 
        item.id === itemId ? { ...item, quantity: newQuantity } : item
      )
    }));
  };

  const calculateTotal = () => {
    return orderData.items.reduce((total, item) => total + (item.quantity * item.rate), 0);
  };

  const handleSubmitOrder = () => {
    const newErrors = {};

    if (!orderData.customerName.trim()) {
      newErrors.customer = 'Customer name is required.';
    }

    if (orderData.items.length === 0) {
      newErrors.items = 'Please add at least one item to the order.';
    }

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    onAddOrder({
      ...orderData,
      total: calculateTotal(),
      timestamp: new Date().toISOString()
    });

    // Reset form
    setOrderData({ customerName: '', orderId: generateOrderId(), items: [] });
    setVoiceInput({ 
      transcript: '', 
      isListening: false, 
      isSupported: voiceInput.isSupported,
      interimTranscript: '',
      finalTranscript: ''
    });
    setManualItem({ item: '', quantity: 1, unit: 'pieces', rate: 0 });
    setErrors({});
    setActiveTab('voice');
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 backdrop-blur-sm flex justify-center items-center z-50 p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden">
        {/* Header */}
        <div className="bg-blue-800 text-white p-6 relative">
          <button
            onClick={onClose}
            className="absolute top-4 right-4 text-white hover:bg-white hover:bg-opacity-20 rounded-full p-2 transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
          <div className="flex items-center space-x-3">
            <ShoppingCart className="w-8 h-8" />
            <div>
              <h2 className="text-2xl font-bold">Create New Order</h2>
              <p className="text-blue-100">Add items using voice or manual input</p>
              {deviceInfo.isMobile && (
                <div className="flex items-center mt-1 text-blue-200 text-sm">
                  <Smartphone className="w-4 h-4 mr-1" />
                  Mobile device detected - {deviceInfo.browser} browser
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="p-6 overflow-y-auto max-h-[calc(90vh-100px)]">
          {/* Customer Information */}
          <div className="mb-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Customer Name *
                </label>
                <input
                  type="text"
                  placeholder="Enter customer name"
                  className={`w-full px-4 py-3 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent ${
                    errors.customer ? 'border-red-500' : 'border-gray-300'
                  }`}
                  value={orderData.customerName}
                  onChange={(e) => setOrderData(prev => ({ ...prev, customerName: e.target.value }))}
                />
                {errors.customer && (
                  <p className="text-red-500 text-sm mt-1 flex items-center">
                    <AlertCircle className="w-4 h-4 mr-1" />
                    {errors.customer}
                  </p>
                )}
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Order ID
                </label>
                <input
                  type="text"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg bg-gray-50"
                  value={orderData.orderId}
                  readOnly
                />
              </div>
            </div>
          </div>

          {/* Input Method Tabs */}
          <div className="mb-6">
            <div className="flex border-b border-gray-200">
              <button
                onClick={() => setActiveTab('voice')}
                className={`px-6 py-3 font-medium text-sm transition-colors ${
                  activeTab === 'voice'
                    ? 'border-b-2 border-blue-500 text-blue-600'
                    : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <Mic className="w-4 h-4 inline mr-2" />
                Voice Input
                {!voiceInput.isSupported && (
                  <span className="ml-1 text-xs text-red-500">(Not Supported)</span>
                )}
              </button>
              <button
                onClick={() => setActiveTab('manual')}
                className={`px-6 py-3 font-medium text-sm transition-colors ${
                  activeTab === 'manual'
                    ? 'border-b-2 border-blue-500 text-blue-600'
                    : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <Edit3 className="w-4 h-4 inline mr-2" />
                Manual Entry
              </button>
            </div>
          </div>

          {/* Voice Input Tab */}
          {activeTab === 'voice' && (
            <div className="mb-6">
              <div className="bg-gray-50 rounded-lg p-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Voice Recognition
                  {deviceInfo.isMobile && deviceInfo.supportLevel === 'supported' && (
                    <span className="ml-2 text-xs text-blue-600 bg-blue-100 px-2 py-1 rounded">
                      Mobile Optimized
                    </span>
                  )}
                </label>

                <textarea
                  ref={textareaRef}
                  placeholder="Transcript will appear here... Try saying: '2 bottles water, 5 pieces apple, 1 kg rice'"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg h-32 resize-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  value={voiceInput.transcript}
                  onChange={(e) => setVoiceInput(prev => ({ 
                    ...prev, 
                    transcript: e.target.value,
                    finalTranscript: e.target.value,
                    interimTranscript: ''
                  }))}
                />

                {/* Interim results display for mobile */}
                {deviceInfo.isMobile && voiceInput.interimTranscript && (
                  <div className="mt-2 p-2 bg-yellow-50 border border-yellow-200 rounded text-sm">
                    <span className="text-yellow-700 font-medium">Listening: </span>
                    <span className="text-gray-600 italic">{voiceInput.interimTranscript}</span>
                  </div>
                )}

                <div className="flex justify-between items-center mt-4">
                  <div className="flex space-x-2">
                    {voiceInput.isSupported ? (
                      voiceInput.isListening ? (
                        <button
                          onClick={stopVoiceRecognition}
                          className="flex items-center bg-red-500 text-white px-4 py-2 rounded-lg hover:bg-red-600 transition-colors"
                        >
                          <MicOff className="w-4 h-4 mr-2" />
                          Stop Recording
                          {deviceInfo.isMobile && (
                            <div className="ml-2 w-2 h-2 bg-white rounded-full animate-pulse"></div>
                          )}
                        </button>
                      ) : (
                        <button
                          onClick={startVoiceRecognition}
                          className="flex items-center bg-green-500 text-white px-4 py-2 rounded-lg hover:bg-green-600 transition-colors"
                        >
                          <Mic className="w-4 h-4 mr-2" />
                          {deviceInfo.isMobile ? 'Tap to Speak' : 'Start Recording'}
                        </button>
                      )
                    ) : (
                      <div className="text-gray-500 text-sm flex items-center">
                        <AlertCircle className="w-4 h-4 mr-1" />
                        Voice recognition not supported in {deviceInfo.browser} browser
                        {deviceInfo.isMobile && ' - Try Chrome or Safari'}
                      </div>
                    )}
                  </div>

                  <button
                    onClick={parseVoiceOrder}
                    disabled={!voiceInput.transcript.trim()}
                    className="bg-blue-500 text-white px-4 py-2 rounded-lg hover:bg-blue-600 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
                  >
                    Parse Order
                  </button>
                </div>

                {/* Mobile-specific instructions */}
                {deviceInfo.isMobile && voiceInput.isSupported && (
                  <div className="mt-3 p-3 bg-blue-50 border border-blue-200 rounded text-sm">
                    <h4 className="font-medium text-blue-800 mb-1">Mobile Tips:</h4>
                    <ul className="text-blue-700 text-xs space-y-1">
                      <li>• Speak clearly in a quiet environment</li>
                      <li>• Allow microphone access when prompted</li>
                      <li>• If it stops, tap "Start Recording" again</li>
                      <li>• For best results, speak one item at a time</li>
                    </ul>
                  </div>
                )}

                {errors.voice && (
                  <p className="text-red-500 text-sm mt-2 flex items-start">
                    <AlertCircle className="w-4 h-4 mr-1 flex-shrink-0 mt-0.5" />
                    <span>{errors.voice}</span>
                  </p>
                )}

                {errors.parse && (
                  <p className="text-red-500 text-sm mt-2 flex items-center">
                    <AlertCircle className="w-4 h-4 mr-1" />
                    {errors.parse}
                  </p>
                )}
              </div>
            </div>
          )}

          {/* Manual Input Tab */}
          {activeTab === 'manual' && (
            <div className="mb-6">
              <div className="bg-gray-50 rounded-lg p-4">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Add Item Manually
                </label>
                <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
                  <input
                    type="text"
                    placeholder="Item name"
                    className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    value={manualItem.item}
                    onChange={(e) => setManualItem(prev => ({ ...prev, item: e.target.value }))}
                  />
                  <input
                    type="number"
                    placeholder="Quantity"
                    min="1"
                    className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    value={manualItem.quantity}
                    onChange={(e) => setManualItem(prev => ({ ...prev, quantity: parseInt(e.target.value) || 1 }))}
                  />
                  <select
                    className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    value={manualItem.unit}
                    onChange={(e) => setManualItem(prev => ({ ...prev, unit: e.target.value }))}
                  >
                    {knownUnits.map(unit => (
                      <option key={unit} value={unit}>{unit}</option>
                    ))}
                  </select>
                  <input
                    type="number"
                    placeholder="Price (₹)"
                    min="0"
                    className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    value={manualItem.rate}
                    onChange={(e) => setManualItem(prev => ({ ...prev, rate: parseFloat(e.target.value) || 0 }))}
                  />
                </div>
                <div className="flex justify-between items-center mt-3">
                  <button
                    onClick={addManualItem}
                    className="flex items-center bg-blue-500 text-white px-4 py-2 rounded-lg hover:bg-blue-600 transition-colors"
                  >
                    <Plus className="w-4 h-4 mr-2" />
                    Add Item
                  </button>
                </div>

                {errors.manual && (
                  <p className="text-red-500 text-sm mt-2 flex items-center">
                    <AlertCircle className="w-4 h-4 mr-1" />
                    {errors.manual}
                  </p>
                )}
              </div>
            </div>
          )}

          {/* Order Items List */}
          {orderData.items.length > 0 && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-800 mb-4">Order Items</h3>
              <div className="bg-white border border-gray-200 rounded-lg overflow-hidden">
                <div className="max-h-60 overflow-y-auto">
                  {orderData.items.map((item, index) => (
                    <div key={item.id} className={`p-4 flex items-center justify-between ${index !== orderData.items.length - 1 ? 'border-b border-gray-100' : ''}`}>
                      <div className="flex-1">
                        <div className="flex items-center space-x-3">
                          <div className="flex-1">
                            <h4 className="font-medium text-gray-900">{item.item}</h4>
                            <p className="text-sm text-gray-500">{item.brand}</p>
                          </div>
                          <div className="flex items-center space-x-2">
                            <button
                              onClick={() => updateItemQuantity(item.id, item.quantity - 1)}
                              className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center hover:bg-gray-200"
                            >
                              -
                            </button>
                            <span className="w-12 text-center">{item.quantity}</span>
                            <button
                              onClick={() => updateItemQuantity(item.id, item.quantity + 1)}
                              className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center hover:bg-gray-200"
                            >
                              +
                            </button>
                            <span className="text-sm text-gray-500 ml-2">{item.unit}</span>
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center space-x-3 ml-4">
                        <div className="text-right">
                          <p className="font-medium text-gray-900">₹{(item.quantity * item.rate).toLocaleString()}</p>
                          <p className="text-sm text-gray-500">₹{item.rate} each</p>
                        </div>
                        <button
                          onClick={() => removeItem(item.id)}
                          className="text-red-500 hover:text-red-700 p-1"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>

                {/* Total */}
                <div className="bg-gray-50 p-4 border-t border-gray-200">
                  <div className="flex justify-between items-center">
                    <span className="text-lg font-semibold text-gray-900">Total:</span>
                    <span className="text-2xl font-bold text-blue-600">₹{calculateTotal().toLocaleString()}</span>
                  </div>
                </div>
              </div>
            </div>
          )}

          {errors.items && (
            <p className="text-red-500 text-sm mb-4 flex items-center">
              <AlertCircle className="w-4 h-4 mr-1" />
              {errors.items}
            </p>
          )}

          {/* Submit Button */}
          <div className="flex justify-end space-x-3">
            <button
              onClick={onClose}
              className="px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleSubmitOrder}
              className="px-6 py-3 bg-gradient-to-r from-blue-600 to-purple-600 text-white rounded-lg hover:from-blue-700 hover:to-purple-700 transition-colors font-medium"
            >
              Create Order
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CreateOrder;
